  ('disabled-e0adf6cd-moex-00028', 'disabled-e0adf6cd', 'disabled-e0adf6cd-moex-114-decd973b', 'sub-disabled-e0adf6cd-01', NULL, 'single_choice', '依司法院大法官解釋及憲法訴訟法規定，關於法官聲請法規範憲法審查之 敘述，下列何者錯誤？', '["依法公布施行之法律，法官應以其為審判之依據，不得認定法律為違憲 而逕行拒絕適用", "憲法之效力既高於法律，法官有優先遵守之義務", "各法院就其審理之案件，對裁判上所應適用之行政命令，認有違憲疑慮 時，應聲請憲法法庭審查", "法官聲請法規範憲法審查，應於聲請書敘明客觀上形成確信法規範違憲 之法律見解"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:14+00:00", "source_pdf_sha1": "0c2a462631d6", "answer_pdf_sha1": "0408f66f88b4", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "303", "s": "0103", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "基礎能力測驗(作文、中華民國憲法及法學緒論)", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 28, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "教育行政"}'::jsonb, NULL),
